import{_ as a,c as i,o,ae as t}from"./chunks/framework.Bw7rlmih.js";const p=JSON.parse('{"title":"CP-017: Requirement Coverage Map","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/atomic/CP-017-requirement-coverage-map.md","filePath":"control-plane/atomic/CP-017-requirement-coverage-map.md"}'),l={name:"control-plane/atomic/CP-017-requirement-coverage-map.md"};function r(n,e,c,d,s,u){return o(),i("div",null,e[0]||(e[0]=[t('<h1 id="cp-017-requirement-coverage-map" tabindex="-1">CP-017: Requirement Coverage Map <a class="header-anchor" href="#cp-017-requirement-coverage-map" aria-label="Permalink to &quot;CP-017: Requirement Coverage Map&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Map requested control-plane requirements to atomic specs for implementation tracking.</p><h2 id="inputs-outputs" tabindex="-1">Inputs / Outputs <a class="header-anchor" href="#inputs-outputs" aria-label="Permalink to &quot;Inputs / Outputs&quot;">​</a></h2><ul><li>Input: requirement statements and feature requests.</li><li>Output: deterministic mapping to atomic spec IDs.</li></ul><h2 id="public-interfaces" tabindex="-1">Public Interfaces <a class="header-anchor" href="#public-interfaces" aria-label="Permalink to &quot;Public Interfaces&quot;">​</a></h2><ul><li>This file is consumed by planning/review process; no runtime API surface.</li></ul><h2 id="data-contracts" tabindex="-1">Data Contracts <a class="header-anchor" href="#data-contracts" aria-label="Permalink to &quot;Data Contracts&quot;">​</a></h2><ul><li>Requirement item -&gt; one or more <code>CP-XXX</code> atomic spec references.</li><li>Every mapped item must reference at least one acceptance-criteria-bearing spec.</li></ul><h2 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h2><ul><li>No requested requirement remains unmapped.</li><li>Mapping references only existing files.</li></ul><h2 id="failure-modes" tabindex="-1">Failure Modes <a class="header-anchor" href="#failure-modes" aria-label="Permalink to &quot;Failure Modes&quot;">​</a></h2><ul><li>stale mapping after spec renames</li><li>missing mapping for newly added requirements</li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><ol><li>Every requirement block has at least one spec reference.</li><li>All references in this file resolve to existing atomic files.</li><li>Mapping is updated before scope changes are implemented.</li></ol><h2 id="coverage-matrix" tabindex="-1">Coverage Matrix <a class="header-anchor" href="#coverage-matrix" aria-label="Permalink to &quot;Coverage Matrix&quot;">​</a></h2><h3 id="remote-backends-and-connectors" tabindex="-1">Remote Backends and Connectors <a class="header-anchor" href="#remote-backends-and-connectors" aria-label="Permalink to &quot;Remote Backends and Connectors&quot;">​</a></h3><ul><li>Vault KV1/KV2/logical/dynamic/transit -&gt; <code>CP-005</code></li><li>AWS SSM/Secrets Manager/AppConfig/S3/DynamoDB -&gt; <code>CP-005</code></li><li>GCP Secret Manager/GCS/Firestore/Runtime Config -&gt; <code>CP-005</code></li><li>Azure Key Vault/App Configuration/Blob/Cosmos -&gt; <code>CP-005</code></li><li>SOPS + key backends -&gt; <code>CP-005</code></li><li>Consul/etcd/Redis + watch hooks -&gt; <code>CP-005</code>, <code>CP-006</code></li><li>Extras (K8s, HTTP ETag, Git ref/file) -&gt; <code>CP-005</code></li></ul><h3 id="caching-rules" tabindex="-1">Caching Rules <a class="header-anchor" href="#caching-rules" aria-label="Permalink to &quot;Caching Rules&quot;">​</a></h3><ul><li>Lease/TTL-aware cache hard rule -&gt; <code>CP-006</code></li><li>SWR + watch invalidation hard rule -&gt; <code>CP-006</code></li></ul><h3 id="control-plane-capabilities" tabindex="-1">Control Plane Capabilities <a class="header-anchor" href="#control-plane-capabilities" aria-label="Permalink to &quot;Control Plane Capabilities&quot;">​</a></h3><ul><li>Store/version schema/template/values/files/policies/bundles -&gt; <code>CP-000</code></li><li>Remote run from server -&gt; <code>CP-007</code></li><li>Pinning and immutable bindings -&gt; <code>CP-003</code></li><li>Value provenance per resolved path -&gt; <code>CP-004</code></li><li>Governance (RBAC, approvals, audit, protected env) -&gt; <code>CP-002</code>, <code>CP-016</code></li></ul><h3 id="core-model" tabindex="-1">Core Model <a class="header-anchor" href="#core-model" aria-label="Permalink to &quot;Core Model&quot;">​</a></h3><ul><li>Project/Environment -&gt; <code>CP-000</code></li><li>Schema@version/Template@version/Values@version/Bundle@version -&gt; <code>CP-000</code></li><li>Policy model -&gt; <code>CP-000</code></li><li>RunRecord -&gt; <code>CP-004</code></li></ul><h3 id="pinning-and-safety" tabindex="-1">Pinning and Safety <a class="header-anchor" href="#pinning-and-safety" aria-label="Permalink to &quot;Pinning and Safety&quot;">​</a></h3><ul><li>Immutable versions -&gt; <code>CP-003</code></li><li>Protected refs with approvals -&gt; <code>CP-003</code>, <code>CP-016</code></li><li>Locked template-schema bindings -&gt; <code>CP-003</code></li><li>Optional signed bundles -&gt; <code>CP-003</code>, <code>CP-008</code></li></ul><h3 id="cli-flow" tabindex="-1">CLI Flow <a class="header-anchor" href="#cli-flow" aria-label="Permalink to &quot;CLI Flow&quot;">​</a></h3><ul><li><code>konfigo login</code> -&gt; <code>CP-002</code>, <code>CP-007</code></li><li><code>konfigo push ...</code> -&gt; <code>CP-007</code></li><li><code>konfigo bundle create --pin</code> -&gt; <code>CP-003</code>, <code>CP-007</code></li><li><code>konfigo run --server ... --bundle ...</code> -&gt; <code>CP-007</code></li></ul><h3 id="offline-mode" tabindex="-1">Offline Mode <a class="header-anchor" href="#offline-mode" aria-label="Permalink to &quot;Offline Mode&quot;">​</a></h3><ul><li>Cached bundle execution -&gt; <code>CP-008</code></li><li>Signature verification for cached artifacts -&gt; <code>CP-008</code></li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><p>If any requirement changes, update this map first, then update only affected atomic specs.</p><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Defining runtime feature behavior directly (this file maps, not specifies).</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>CP-000 through CP-016.</li></ul>',36)]))}const m=a(l,[["render",r]]);export{p as __pageData,m as default};
